mapper.select:
select c.* from ( select a.system, b.jobid, b.db, b.owner, b.table_name, b.seq1, b.seq2, b.seq3 , sum(CASE WHEN b.steptype in ('EXE_DELETE', 'EXE_UPDATE') THEN b.execnt ELSE 0 END) as delcnt , sum(CASE WHEN b.steptype='EXE_ARCHIVE' THEN b.execnt ELSE 0 END) as arccnt , sum(CASE WHEN b.steptype in ('EXE_ARC_DELETE') THEN b.execnt ELSE 0 END) as delarccnt from cotdl.tbl_piiorder a, cotdl.tbl_piiordersteptable b where a.status = 'Ended OK' and a.orderid = b.orderid and b.steptype in ('EXE_ARCHIVE', 'EXE_DELETE', 'EXE_UPDATE')
group by b.db, b.owner, b.table_name, a.system, b.jobid, b.seq1, b.seq2, b.seq3 ) as c
order by db, owner, table_name, jobid limit #{offset}, #{amount}


select count(1) 
  from cotdl.tbl_piiordersteptable a
     , cotdl.tbl_piiordersteptablewait b
 where a.orderid = b.orderid and a.jobid = b.jobid and a.version = b.version and type='PRE' and a.stepid= b.stepid
   and a.db= b.db_w and a.owner= b.owner_w and a.table_name= b.table_name_w
   and b.db= #{db, jdbcType=VARCHAR} and b.owner= #{owner, jdbcType=VARCHAR} and b.table_name= #{table_name, jdbcType=VARCHAR}
   and a.status != 'Ended OK'
   and a.orderid = #{orderid} 
   and a.stepid = #{stepid, jdbcType=VARCHAR}

		select orderid, status, forceokflag,  DATE_FORMAT(basedate,'%Y/%m/%d') as basedate, jobid, version, stepid, stepname, steptype, stepseq, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, arccnt, arctime,  DATE_FORMAT(arcstart,'%Y/%m/%d %H:%i:%s') as arcstart,  DATE_FORMAT(arcend,'%Y/%m/%d %H:%i:%s') as arcend, execnt, exetime,  DATE_FORMAT(exestart,'%Y/%m/%d %H:%i:%s') as exestart,  DATE_FORMAT(exeend,'%Y/%m/%d %H:%i:%s') as exeend,  sqlmsg, hintselect, hintinsert, uval1, uval2, uval3, uval4, uval5
		  from cotdl.tbl_piiordersteptable 
         where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR} and db= #{db, jdbcType=VARCHAR} and owner= #{owner, jdbcType=VARCHAR} and table_name= #{table_name, jdbcType=VARCHAR}

		select orderid, status, forceokflag,  DATE_FORMAT(basedate,'%Y/%m/%d') as basedate, jobid, version, stepid, stepname, steptype, stepseq, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, arccnt, arctime,  DATE_FORMAT(arcstart,'%Y/%m/%d %H:%i:%s') as arcstart,  DATE_FORMAT(arcend,'%Y/%m/%d %H:%i:%s') as arcend, execnt, exetime,  DATE_FORMAT(exestart,'%Y/%m/%d %H:%i:%s') as exestart,  DATE_FORMAT(exeend,'%Y/%m/%d %H:%i:%s') as exeend,  sqlmsg, hintselect, hintinsert, uval1, uval2, uval3, uval4, uval5
		  from cotdl.tbl_piiordersteptable 
         where orderid= #{orderid} and stepid= #{stepid, jdbcType=VARCHAR} and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

select count(1)
from cotdl.tbl_piiordersteptable
where jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and exetype= #{exetype}
  and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

		select execnt
		  from cotdl.tbl_piiordersteptable 
         where orderid= #{orderid} and exetype= #{exetype, jdbcType=VARCHAR} and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

		select count(1)
		  from cotdl.tbl_piiordersteptable 
         where orderid= #{orderid} and exetype= #{exetype, jdbcType=VARCHAR} and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

		
		select count(1)
		  from cotdl.tbl_piiordersteptable 
         where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR} 
           and status = 'Ended not OK'
           and (seq1 < #{seq1} 
            	or (seq1 = #{seq1} and seq2 < #{seq2})
            	or (seq1 = #{seq1} and seq2 = #{seq2} and seq3 <  #{seq3})
            )

		
		select count(1)
		  from cotdl.tbl_piiordersteptable 
         where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR} 
           and status = 'Ended not OK'
           and (seq1 > #{seq1} 
              	or (seq1 = #{seq1} and seq2 > #{seq2})
            	or (seq1 = #{seq1} and seq2 = #{seq2} and seq3 >  #{seq3})
            )

mapper.delete:
delete from cotdl.tbl_piiordersteptable
 where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR} 
   and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

mapper.update:
update cotdl.tbl_piiordersteptable
   set 
		status= #{status, jdbcType=VARCHAR},
		exetime= TIME_FORMAT(TIMEDIFF(now(),exestart),'%H : %i : %s'),
		exeend= NOW(),
		execnt= #{execnt, jdbcType=VARCHAR},
		sqlmsg= #{sqlmsg, jdbcType=VARCHAR}
 where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR} 
   and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

update cotdl.tbl_piiordersteptable
   set 
		status= #{status, jdbcType=VARCHAR},
		exetime= TIME_FORMAT(TIMEDIFF(now(),exestart),'%H : %i : %s'),
		exeend= NOW(),
		
		sqlmsg= #{sqlmsg, jdbcType=VARCHAR}
 where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} 
   and steptype in ('EXE_DELETE', 'EXE_UPDATE') 
   and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

update cotdl.tbl_piiordersteptable
   set 
		execnt= #{execnt, jdbcType=VARCHAR}
where orderid= #{orderid} and stepid= #{stepid, jdbcType=VARCHAR} 
  and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

update cotdl.tbl_piiordersteptable
   set 
	   forceokflag= #{forceokflag, jdbcType=VARCHAR}
 where orderid= #{orderid} and jobid= #{jobid, jdbcType=VARCHAR} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid, jdbcType=VARCHAR, jdbcType=VARCHAR} 
   and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

mapper.select:
select count(1)
from (
		 select orderid, status
		   from cotdl.tbl_piiordersteptable
		  where orderid = #{orderid}
			and steptype= 'EXE_RESTORE'
		  order by orderid, jobid, version, stepseq, seq1 , seq2 , seq3
		 limit 10
	 ) t
where status != 'Ended OK'
